import { useCallback, useEffect, useRef } from 'react'
import {
  ReactFlow,
  Background,
  Controls,
  MiniMap,
  addEdge,
  applyNodeChanges,
  applyEdgeChanges,
  Connection,
  NodeChange,
  EdgeChange,
  Edge,
  Node,
  BackgroundVariant,
} from '@xyflow/react'
import '@xyflow/react/dist/style.css'
import { Box, Chip, Typography } from '@mui/material'
import { useTheme } from '@mui/material/styles'

// Generated by: npm run generate-api
import { useGetDesign, useUpdateDesign } from '../../../api/designs/designs'
import { useDesignStore } from '../designStore'
import { NodeType, SystemNodeData } from '../../../types'
import SystemNode from './nodes/SystemNode'

const nodeTypes = { systemNode: SystemNode }

const TOOLBAR_NODES: { type: NodeType; label: string }[] = [
  { type: 'client',        label: 'Client' },
  { type: 'api_gateway',   label: 'API Gateway' },
  { type: 'load_balancer', label: 'Load Balancer' },
  { type: 'service',       label: 'Service' },
  { type: 'database',      label: 'Database' },
  { type: 'cache',         label: 'Cache' },
  { type: 'queue',         label: 'Queue' },
]

export default function FlowCanvas() {
  const theme = useTheme()
  const isDark = theme.palette.mode === 'dark'

  const { activeDesignId, nodes, edges, setNodes, setEdges } = useDesignStore()
  const saveTimer = useRef<ReturnType<typeof setTimeout> | null>(null)
  const initializedForRef = useRef<string | null>(null)

  const { data: design, isLoading } = useGetDesign(activeDesignId!, {
    query: { enabled: !!activeDesignId, staleTime: Infinity },
  })

  useEffect(() => {
    if (design && activeDesignId && activeDesignId !== initializedForRef.current) {
      initializedForRef.current = activeDesignId
      setNodes((design.nodes ?? []) as Node<SystemNodeData>[])
      setEdges((design.edges ?? []) as Edge[])
    }
  }, [design, activeDesignId, setNodes, setEdges])

  const { mutate: updateDesign } = useUpdateDesign()

  const debouncedSave = useCallback(
    (n: Node<SystemNodeData>[], e: Edge[]) => {
      if (!activeDesignId) return
      if (saveTimer.current) clearTimeout(saveTimer.current)
      saveTimer.current = setTimeout(() => {
        updateDesign({ designId: activeDesignId, data: { nodes: n, edges: e } })
      }, 1500)
    },
    [activeDesignId, updateDesign]
  )

  const onNodesChange = useCallback(
    (changes: NodeChange<Node<SystemNodeData>>[]) => {
      const updated = applyNodeChanges(changes, nodes)
      setNodes(updated)
      debouncedSave(updated, edges)
    },
    [nodes, edges, setNodes, debouncedSave]
  )

  const onEdgesChange = useCallback(
    (changes: EdgeChange[]) => {
      const updated = applyEdgeChanges(changes, edges)
      setEdges(updated)
      debouncedSave(nodes, updated)
    },
    [nodes, edges, setEdges, debouncedSave]
  )

  const onConnect = useCallback(
    (connection: Connection) => {
      const updated = addEdge(connection, edges)
      setEdges(updated)
      debouncedSave(nodes, updated)
    },
    [nodes, edges, setEdges, debouncedSave]
  )

  const addNode = useCallback(
    (nodeType: NodeType) => {
      const id = `${nodeType}-${Date.now()}`
      const label = nodeType.replace(/_/g, ' ').replace(/\b\w/g, (c) => c.toUpperCase())
      const newNode: Node<SystemNodeData> = {
        id,
        type: 'systemNode',
        position: { x: 100 + Math.random() * 500, y: 100 + Math.random() * 300 },
        data: { label, nodeType },
      }
      const updated = [...nodes, newNode]
      setNodes(updated)
      debouncedSave(updated, edges)
    },
    [nodes, edges, setNodes, debouncedSave]
  )

  if (!activeDesignId) {
    return (
      <Box
        sx={{
          flex: 1,
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          bgcolor: 'background.default',
          color: 'text.disabled',
          gap: 1,
        }}
      >
        <Typography fontSize={40}>🖥️</Typography>
        <Typography variant="body2">Select or create a design to get started</Typography>
      </Box>
    )
  }

  if (isLoading) {
    return (
      <Box sx={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', bgcolor: 'background.default' }}>
        <Typography variant="body2" color="text.secondary">Loading...</Typography>
      </Box>
    )
  }

  return (
    <Box sx={{ flex: 1, display: 'flex', flexDirection: 'column', minWidth: 0 }}>
      {/* Toolbar */}
      <Box
        sx={{
          display: 'flex',
          alignItems: 'center',
          gap: 0.75,
          px: 2,
          py: 1,
          bgcolor: 'background.paper',
          borderBottom: 1,
          borderColor: 'divider',
          flexWrap: 'wrap',
        }}
      >
        <Typography variant="caption" color="text.secondary" sx={{ mr: 0.5 }}>
          Add:
        </Typography>
        {TOOLBAR_NODES.map(({ type, label }) => (
          <Chip
            key={type}
            label={label}
            size="small"
            onClick={() => addNode(type)}
            clickable
            variant="outlined"
            sx={{ fontSize: 11 }}
          />
        ))}
      </Box>

      {/* Canvas */}
      <Box sx={{ flex: 1 }}>
        <ReactFlow
          nodes={nodes}
          edges={edges}
          onNodesChange={onNodesChange}
          onEdgesChange={onEdgesChange}
          onConnect={onConnect}
          nodeTypes={nodeTypes}
          fitView
          fitViewOptions={{ padding: 0.2 }}
          style={{ background: theme.palette.background.default }}
        >
          <Background
            variant={BackgroundVariant.Dots}
            gap={16}
            size={1}
            color={isDark ? '#334155' : '#e2e8f0'}
          />
          <Controls />
          <MiniMap
            nodeStrokeWidth={3}
            zoomable
            pannable
            style={{ background: theme.palette.background.paper }}
          />
        </ReactFlow>
      </Box>
    </Box>
  )
}
